properties.query:
let timeframe = 20m;
let ADWSConnections=materialize(
    DeviceNetworkEvents
    | where ingestion_time() >= ago(timeframe)
    | where ActionType == "ConnectionSuccess"
    | where RemotePort == 9389
    | where not(ipv4_is_in_range(RemoteIP, "127.0.0.0/8"))
    | extend InitiatingProcessFileName=tolower(InitiatingProcessFileName)
    // filtering processes that are expected to connect to ADWS
    | where not(InitiatingProcessFolderPath startswith @"c:\windows\system32\windowspowershell\")
    | where not(InitiatingProcessFolderPath startswith @"c:\windows\syswow64\windowspowershell\")
    | where not(InitiatingProcessFolderPath startswith @"c:\program files\powershell\" and InitiatingProcessFileName =~ "pwsh.exe")
    | where not(InitiatingProcessFolderPath startswith @"c:\program files\microsoft monitoring agent\")
    | where not(InitiatingProcessFolderPath startswith @"c:\windows\system32\dsac.exe")
    | where not (InitiatingProcessFileName =~ "rssrdp64.exe" and InitiatingProcessFolderPath contains @"\appdata\local\securelink\slinksw")
);
let ADWSFileNames=materialize(
    ADWSConnections
    | distinct InitiatingProcessFileName
);
// Look for processes that inject into a process that makes an ADWS connection.
let InjectorProcesses=materialize(
    DeviceEvents
    | where ingestion_time() >= ago(timeframe)
    | where not(isempty(FileName))
    // Look for actions associated with process injection.
    | where ActionType in~ ("CreateRemoteThreadApiCall", "MemoryRemoteProtect","NtAllocateVirtualMemoryApiCall", "NtAllocateVirtualMemoryRemoteApiCall", "NtMapViewOfSectionRemoteApiCall", "NtProtectVirtualMemoryApiCall", "SetThreadContextRemoteApiCall", "QueueUserApcRemoteApiCall")
    | where FileName in~ (ADWSFileNames)
    | where not(InitiatingProcessFolderPath startswith @"c:\program files\vmware\vmware tools" and InitiatingProcessFileName =~ "vmtoolsd.exe")
    | where not(InitiatingProcessFolderPath =~ @"C:\Windows\System32" and InitiatingProcessFileName =~ "csrss.exe")
    | where not(InitiatingProcessFolderPath =~ @"C:\Windows\System32\csrss.exe")
    | where not(InitiatingProcessFolderPath startswith @"c:\program files\microsoft azure ad sync\" and InitiatingProcessFileName =~ "miiserver.exe")
    | where not (InitiatingProcessFileName =~ "RssHookx64Z.exe" and InitiatingProcessFolderPath contains @"\appdata\local\securelink\slinksw")
    | extend FileName=tolower(FileName)
    | lookup kind=inner ADWSConnections on DeviceId, $left.ProcessId == $right.InitiatingProcessId, $left.FileName == $right.InitiatingProcessFileName
    | project DeviceId, ProcessId, FileName, InjectorProcessId=InitiatingProcessId, InjectorFileName=InitiatingProcessFileName, InjectorProcessFolderPath=InitiatingProcessFolderPath, InjectorActionType=ActionType
);
// Find ADWS connections from processes that were injected into by another process.
ADWSConnections
| lookup kind=inner InjectorProcesses on DeviceId, $left.InitiatingProcessId == $right.ProcessId, $left.InitiatingProcessFileName == $right.FileName
| extend InitiatingProcessDirectory = substring(InitiatingProcessFolderPath, 0, strlen(InitiatingProcessFolderPath) - strlen(InitiatingProcessFileName) - 1)
| summarize arg_min(TimeGenerated,*), InjectionMethods=make_set(InjectorActionType) by DeviceName, DeviceId, InitiatingProcessFileName, InitiatingProcessDirectory, InitiatingProcessAccountUpn, InitiatingProcessId, InjectorFileName, InjectorProcessFolderPath
| extend HostName= tostring(split(DeviceName, '.', 0)[0]), DnsDomain = tostring(strcat_array(array_slice(split(DeviceName, '.'), 1, -1), '.'))
